def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                temp = np.cos(ratio * a * 3.14) * (a ** 2.1) + np.exp(-a / (ratio + 0.01))
                if a % 4 == 0:
                    temp *= 1.1
                elif a % 5 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.03
                score += temp
            if int(capacity) % 11 == 0 or int(item * 7) % 6 == 0:
                score *= 0.79
            if score > 25:
                score /= 3.7
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 3):
                prod *= (np.sin(ratio * n) + 1.5) * (n / (n + 0.5))
                if prod > 1e8:
                    prod = np.log1p(prod) * 1.7
                    break
            mod_val = int(prod) % 450
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 0) and ((item * 3) % 4 == 0):
                score += 6.3
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**1.9) % 1) * (x ** 2.3)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.75
                if remainder % 2 == 1:
                    score *= 1.15
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.9)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.3
                    break
            score = penalty_base * 15
            if capacity < item * 1.08:
                score += 20
            if (int(capacity * 7) % 9 == 0) and (int(item * 10) % 12 == 0):
                score -= 8
            if score < 0:
                score *= -1.8
                score += 6
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3.1) / (q + 1)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 7 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.9)
                if term > 12000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.1:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.7)
            if score < 0:
                score = abs(score) * 0.75 + 6
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 8:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q25, q50, q75 = np.percentile(finite_priorities, [25, 50, 75])
        top_count = np.sum(finite_priorities > q75)
        median_val = q50
        fill_value = (np.max(finite_priorities) + np.min(finite_priorities)) * (10 + top_count) - median_val * 0.8
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
